-- Step 1: Delete the 4 duplicate billing items (NULL accountCode, second import)
DELETE FROM billing_items WHERE id IN (32067, 32068, 32069, 32355);

-- Step 2: Fix item 210 (Voice - Direct In Dial Numbers $2.00) → assign to SSWS5JSC (DID Australia service)
UPDATE billing_items SET serviceExternalId = 'SSWS5JSC' WHERE id = 210;

-- Step 3: Fix item 211 (Voice - Services $25.00 = UCXcel Essential) → assign to SSJMFUF3
UPDATE billing_items SET serviceExternalId = 'SSJMFUF3' WHERE id = 211;

-- Step 4: Recalculate monthlyRevenue for all affected services
-- S0332 (NBN): only item 499 ($120) remains
UPDATE services SET monthlyRevenue = (
  SELECT COALESCE(SUM(lineAmount), 0) FROM billing_items WHERE serviceExternalId = 'S0332'
) WHERE externalId = 'S0332';

-- S7381 (IP Tel Single Number): no items remain after deletes
UPDATE services SET monthlyRevenue = (
  SELECT COALESCE(SUM(lineAmount), 0) FROM billing_items WHERE serviceExternalId = 'S7381'
) WHERE externalId = 'S7381';

-- SSWS5JSC (DID Australia): items 209 ($3.79) + 210 ($2.00) = $5.79
UPDATE services SET monthlyRevenue = (
  SELECT COALESCE(SUM(lineAmount), 0) FROM billing_items WHERE serviceExternalId = 'SSWS5JSC'
) WHERE externalId = 'SSWS5JSC';

-- SSJMFUF3 (UCXcel Essential): item 211 ($25.00)
UPDATE services SET monthlyRevenue = (
  SELECT COALESCE(SUM(lineAmount), 0) FROM billing_items WHERE serviceExternalId = 'SSJMFUF3'
) WHERE externalId = 'SSJMFUF3';

